export const HasIslands = ({ children }: { children: any }): any => {
  const c = contextStorage.getStore()
  if (!c) {
    throw new Error('No context found')
  }
  return <>{c.get(IMPORTING_ISLANDS_ID) && children}</>
}

const contentType = (request: Record<string | symbol, any>): string => {
  return (
    (request[headersKey] ||= newHeadersFromIncoming(request[incomingKey])).get('content-type') || ''
  )
}

const getIp = (ctx: Context) => {
  return (
    ctx.req.header('x-forwarded-for')?.split(',')[0]?.trim() ||
    ctx.req.header('x-real-ip') ||
    ctx.env.incoming.socket.remoteAddress ||
    null
  );
};

const useSessionStorage = <Data, E extends SessionStorageEnv<Data>>(
set: Set<E, Storage<Data>>
): MiddlewareHandler<E> =>
createMiddleware<E>((c, next) => {
  c.set('sessionStorage', typeof set === 'function' ? set(c) : set)
  return next()
})

